// 編譯器範例 (C#)
// 先看過一遍，再從 main() 開始
// 速度快：只要 50ms

# 基本 for 迴圈
for i in range(5):
    print(i)  # 0, 1, 2, 3, 4

# 遍歷 list
fruits = ["apple", "banana"]
for fruit in fruits:
    print(fruit)

# 搭配 enumerate
for idx, fruit in enumerate(fruits):
    print(f"{idx}: {fruit}")

# 綜合練習：建立一個學生管理系統
class Student:
    def __init__(self, name, scores):
        self.name = name
        self.scores = scores  # list

    def average(self):
        return sum(self.scores) / len(self.scores)

    def grade(self):
        avg = self.average()
        if avg >= 90:
            return "A"
        elif avg >= 80:
            return "B"
        elif avg >= 70:
            return "C"
        else:
            return "F"

# 建立學生 objects
students = [
    Student("Alice", [95, 88, 92]),
    Student("Bob", [78, 85, 72]),
    Student("Charlie", [60, 55, 68])
]

# 用 for 迴圈印出每個學生的成績
for s in students:
    print(f"{s.name}: {s.average():.1f} ({s.grade()})")
